/**
 * Email notification handler — formats and sends email notifications
 * for order status changes.
 *
 * Architecture: Subscribes to order events via EventBus, consistent with
 * the codebase's event-driven notification pattern. This handler focuses
 * on email-specific formatting and delivery, complementing the general
 * NotificationService.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderStatusChangedEvent, OrderCreatedEvent } from '../events/event-types.js';
import type { OrderStatus } from '../models/order.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

const STATUS_DETAILS: Record<OrderStatus, { label: string; message: string }> = {
  pending: {
    label: 'Order Received',
    message: 'We have received your order and it is being reviewed.',
  },
  confirmed: {
    label: 'Order Confirmed',
    message: 'Your order has been confirmed and is being prepared.',
  },
  shipped: {
    label: 'Order Shipped',
    message: 'Your order is on its way! You will receive tracking information shortly.',
  },
  delivered: {
    label: 'Order Delivered',
    message: 'Your order has been delivered. Thank you for your purchase!',
  },
  cancelled: {
    label: 'Order Cancelled',
    message: 'Your order has been cancelled. If you did not request this, please contact support.',
  },
};

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });
  }

  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const details = STATUS_DETAILS[event.newStatus as OrderStatus];
    if (!details) {
      this.logger.warn(`Unknown order status: ${event.newStatus}`);
      return;
    }

    this.logger.info(
      `Sending email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const subject = `${details.label} - Order #${event.order.id}`;
    const textBody = [
      `Order #${event.order.id} - ${details.label}`,
      '',
      details.message,
      '',
      `Previous status: ${event.previousStatus}`,
      `New status: ${event.newStatus}`,
    ].join('\n');

    const htmlBody = [
      `<h2>Order #${event.order.id} - ${details.label}</h2>`,
      `<p>${details.message}</p>`,
      `<p><strong>Previous status:</strong> ${event.previousStatus}</p>`,
      `<p><strong>New status:</strong> ${event.newStatus}</p>`,
    ].join('\n');

    this.sendEmail({
      to: event.order.userId,
      subject,
      htmlBody,
      textBody,
    });
  }

  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    const itemLines = event.order.items.map(
      (item) => `${item.name} x${item.quantity} - $${(item.quantity * item.unitPrice).toFixed(2)}`,
    );

    const subject = `Order Confirmation - Order #${event.order.id}`;
    const textBody = [
      `Order #${event.order.id} - Confirmation`,
      '',
      'Thank you for your order! Here is your order summary:',
      '',
      ...itemLines,
      '',
      `Total: $${event.order.total.toFixed(2)}`,
    ].join('\n');

    const htmlBody = [
      `<h2>Order #${event.order.id} - Confirmation</h2>`,
      '<p>Thank you for your order! Here is your order summary:</p>',
      '<ul>',
      ...event.order.items.map(
        (item) =>
          `<li>${item.name} x${item.quantity} - $${(item.quantity * item.unitPrice).toFixed(2)}</li>`,
      ),
      '</ul>',
      `<p><strong>Total:</strong> $${event.order.total.toFixed(2)}</p>`,
    ].join('\n');

    this.sendEmail({
      to: event.user.email,
      subject,
      htmlBody,
      textBody,
    });
  }

  private sendEmail(params: Omit<EmailMessage, 'sentAt'>): void {
    const email: EmailMessage = {
      ...params,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent to ${params.to}: ${params.subject}`);
  }

  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  getSentEmailsFor(recipient: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.to === recipient);
  }

  getSentEmailCount(): number {
    return this.sentEmails.length;
  }

  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { EmailNotificationHandler } from '../../src/notifications/email-notification.handler.js';
import type { OrderStatusChangedEvent, OrderCreatedEvent } from '../../src/events/event-types.js';

describe('EmailNotificationHandler', () => {
  let eventBus: EventBus;
  let handler: EmailNotificationHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    handler = new EmailNotificationHandler(eventBus);
  });

  describe('order:status-changed emails', () => {
    it('should send email when order status changes to confirmed', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toContain('Order Confirmed');
      expect(emails[0]?.subject).toContain('order-1');
      expect(emails[0]?.textBody).toContain('confirmed and is being prepared');
      expect(emails[0]?.htmlBody).toContain('<h2>');
    });

    it('should send email when order status changes to shipped', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'bob@example.com',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Order Shipped');
      expect(emails[0]?.textBody).toContain('on its way');
    });

    it('should send email when order is delivered', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-3',
          userId: 'carol@example.com',
          items: [],
          total: 100,
          status: 'delivered',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'shipped',
        newStatus: 'delivered',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Order Delivered');
      expect(emails[0]?.textBody).toContain('has been delivered');
    });

    it('should send email when order is cancelled', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-4',
          userId: 'dave@example.com',
          items: [],
          total: 75,
          status: 'cancelled',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'cancelled',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Order Cancelled');
      expect(emails[0]?.textBody).toContain('has been cancelled');
    });

    it('should include previous and new status in email body', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails[0]?.textBody).toContain('Previous status: confirmed');
      expect(emails[0]?.textBody).toContain('New status: shipped');
      expect(emails[0]?.htmlBody).toContain('confirmed');
      expect(emails[0]?.htmlBody).toContain('shipped');
    });
  });

  describe('order:created emails', () => {
    it('should send confirmation email when order is created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.textBody).toContain('Widget x2');
      expect(emails[0]?.textBody).toContain('$20.00');
      expect(emails[0]?.htmlBody).toContain('<li>');
    });

    it('should include all items in confirmation email', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails[0]?.textBody).toContain('Widget x2');
      expect(emails[0]?.textBody).toContain('Gadget x1');
      expect(emails[0]?.textBody).toContain('$45.00');
    });
  });

  describe('email management', () => {
    it('should track sent email count', async () => {
      expect(handler.getSentEmailCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getSentEmailCount()).toBe(1);
    });

    it('should filter emails by recipient', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getSentEmailsFor('alice@example.com')).toHaveLength(1);
      expect(handler.getSentEmailsFor('bob@example.com')).toHaveLength(0);
    });

    it('should clear sent emails', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      handler.clearSentEmails();
      expect(handler.getSentEmailCount()).toBe(0);
    });
  });

  describe('integration with EventBus', () => {
    it('should coexist with other EventBus subscribers', async () => {
      const otherEvents: string[] = [];
      eventBus.on('order:status-changed', (event) => {
        otherEvents.push(event.type);
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      // Both handlers should have received the event
      expect(handler.getSentEmailCount()).toBe(1);
      expect(otherEvents).toHaveLength(1);
    });

    it('should handle full order lifecycle via email', async () => {
      const makeStatusEvent = (
        previousStatus: string,
        newStatus: string,
      ): OrderStatusChangedEvent => ({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'alice@example.com',
          items: [],
          total: 50,
          status: newStatus as any,
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus,
        newStatus,
        timestamp: new Date(),
      });

      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));
      await eventBus.emit(makeStatusEvent('confirmed', 'shipped'));
      await eventBus.emit(makeStatusEvent('shipped', 'delivered'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(3);
      expect(emails[0]?.subject).toContain('Order Confirmed');
      expect(emails[1]?.subject).toContain('Order Shipped');
      expect(emails[2]?.subject).toContain('Order Delivered');
    });
  });
});

